<template>
  <div class="settings">
    <v-col cols="12">
      <h1>Settings</h1>
      <h2>General</h2>
      <v-divider></v-divider>
      <v-switch v-model="isDark" :label="isDarkThemeLabel"></v-switch>
      <v-switch v-model="isMiniNav" :label="isMiniNavLabel"></v-switch>
      <v-switch
        v-model="isExpandOnHover"
        :label="isExpandOnHoverLabel"
        color="secondary"
      >
      </v-switch>
      <h2>Colors</h2>
      <v-divider></v-divider>
      <v-container>
        <v-col cols="12" lg="6" md="8" class="sticky-theme-picker mx-auto">
          <v-card class="elevation-16">
            <v-card-title>
              <v-icon large left>
                mdi-palette
              </v-icon>
              <span class="title font-weight-light"> Setup theme color </span>
            </v-card-title>
            <v-card-subtitle>
              Pick your favorite color:
              <span class="font-weight-bold">{{ selectedThemeType }}</span>
            </v-card-subtitle>
            <v-divider class="mx-4"></v-divider>

            <v-card-text>
              <v-card
                :color="theme.primary.color"
                class="mb-4"
                elevation="4"
                @click="selectedThemeType = 'primary'"
              >
                <v-card-text :class="[theme.primary.contrast]">
                  Primary
                </v-card-text>
              </v-card>
              <v-card
                :color="theme.secondary.color"
                elevation="4"
                @click="selectedThemeType = 'secondary'"
              >
                <v-card-text :class="[theme.secondary.contrast]">
                  Secondary
                </v-card-text>
              </v-card>
            </v-card-text>
            <v-card-actions>
              <v-btn text color="primary" @click="onApplyPicker">
                Apply
              </v-btn>
              <v-btn text color="secondary" @click="onResetPicker">
                Reset
              </v-btn>
            </v-card-actions>
          </v-card>
        </v-col>

        <v-row>
          <v-col cols="6" md="4" v-for="color in colors" :key="color.name">
            <v-card
              flat
              tile
              v-for="subColor in color.subColors"
              :key="subColor.value"
              :class="[color.name, subColor.subName]"
              @click="onChooseColor(color.name, subColor)"
            >
              <v-card-text :class="[subColor.contrast]">
                {{ color.name }} {{ subColor.subName }}
              </v-card-text>
            </v-card>
          </v-col>
        </v-row>
      </v-container>
    </v-col>
  </div>
</template>

<script>
import colors from "vuetify/lib/util/colors";

export default {
  created() {
    let tempColors = { ...colors };
    delete tempColors.shades;
    delete tempColors.grey;

    for (const [key, iter] of Object.entries(tempColors)) {
      const name = this.convertCamelToKebab(key);
      this.colors.push({ name, subColors: [] });
      for (const [subKey, value] of Object.entries(iter)) {
        const color = this.colors.find((c) => c.name === name);
        color.subColors.push({
          subName: this.convertCamelToKebab(subKey),
          contrast: this.getColorContrast(value),
          value,
        });
      }
    }
  },
  data() {
    return {
      theme: {
        primary: {},
        secondary: {},
      },
      selectedThemeType: "primary",
      colors: [],
    };
  },
  computed: {
    isDarkThemeLabel() {
      return this.isDark ? "Dark" : "Light";
    },
    isMiniNavLabel() {
      return this.isMiniNav ? "Mini" : "Full";
    },
    isExpandOnHoverLabel() {
      return this.isExpandOnHover ? "Expand" : "Not Expand";
    },
    isDark: {
      get() {
        return this.$store.state.isDark;
      },
      set(value) {
        this.$store.commit("updateIsDark", value);
      },
    },
    isMiniNav: {
      get() {
        return this.$store.state.isMiniNav;
      },
      set(value) {
        this.$store.commit("updateIsMiniNav", value);
      },
    },
    isExpandOnHover: {
      get() {
        return this.$store.state.isExpandOnHover;
      },
      set(value) {
        this.$store.commit("updateIsExpandOnHover", value);
      },
    },
  },
  methods: {
    convertCamelToKebab(string) {
      return string
        .replace(/([a-z0-9])([A-Z])/g, "$1-$2")
        .replace(/([a-z])([0-9])/g, "$1-$2")
        .toLowerCase();
    },
    getColorContrast(hex) {
      let r = parseInt(hex.substr(1, 2), 16);
      let g = parseInt(hex.substr(3, 2), 16);
      let b = parseInt(hex.substr(5, 2), 16);
      const yiq = (r * 299 + g * 587 + b * 114) / 1000;
      return yiq >= 128 ? "black--text" : "white--text";
    },
    onChooseColor(name, color) {
      this.theme[this.selectedThemeType] = {
        color: `${name} ${color.subName}`,
        contrast: color.contrast,
        value: color.value,
      };
    },
    onResetPicker() {
      this.theme = {
        primary: {},
        secondary: {},
      };
    },
    onApplyPicker() {
      if (this.theme.primary.value && this.theme.primary.value) {
        const primary = this.theme.primary.value;
        const secondary = this.theme.secondary.value;

        this.$vuetify.theme.themes.light.primary = primary;
        this.$vuetify.theme.themes.light.secondary = secondary;
        this.$vuetify.theme.themes.dark.primary = secondary;
        this.$vuetify.theme.themes.dark.secondary = primary;

        localStorage.setItem("theme-light-primary", primary);
        localStorage.setItem("theme-light-secondary", secondary);
        localStorage.setItem("theme-dark-primary", secondary);
        localStorage.setItem("theme-dark-secondary", primary);
      } else {
        alert("Please pick primary and secondary color");
      }
    },
  },
};
</script>

<style lang="scss" scoped>
.sticky-theme-picker {
  position: sticky;
  top: 84px;
  z-index: 1;
}
</style>
